SELECT model_id, SUM(quantity) AS total_quantity
FROM equipment_inventory
GROUP BY model_id;

SELECT COUNT(performance_status) AS alert_count
FROM equipment_performance
WHERE alert_generated = 1;

SELECT SUM(manufacturing_cost) AS total_manufacturing_cost
FROM equipment_manufacturing
WHERE model_id = 1;

SELECT model_id
FROM equipment_inventory
WHERE last_inventory_check > '2022-01-16';

SELECT SUM(quantity) AS total_quantity
FROM equipment_inventory
WHERE model_id = 1;

SELECT COUNT(*) AS total_new_items
FROM equipment_inventory
WHERE condition = 'new';

SELECT performance_metric
FROM equipment_performance
WHERE performance_id = 1;

SELECT MAX(value) AS max_speed
FROM equipment_performance
WHERE performance_metric = 'Speed' AND model_id = 0;
